const msg = $('Telegram Trigger1').first().json.channel_post;
if (!msg) return [];

let type = 'other';
let file_id = null;
let caption = '';
let entities = [];

// photo
if (msg.photo?.length) {
  type = 'photo';
  file_id = msg.photo[msg.photo.length - 1].file_id;
  caption = msg.caption || '';
  entities = msg.caption_entities || [];
}
// video
else if (msg.video) {
  type = 'video';
  file_id = msg.video.file_id;
  caption = msg.caption || '';
  entities = msg.caption_entities || [];
}
// text
else if (msg.text) {
  type = 'text';
  caption = msg.text || '';
  entities = msg.entities || [];
}
// document
else if (msg.document) {
  type = 'document';
  file_id = msg.document.file_id;
  caption = msg.caption || '';
  entities = msg.caption_entities || [];
}
// other
else {
  type = 'other';
  caption = '';
  entities = msg.caption_entities || msg.entities || [];
}

return [{
  json: {
    media_group_id: msg.media_group_id || null,
    message_id: msg.message_id,
    reply_id: msg.reply_to_message?.message_id || null,
    chat_id: String(msg.chat?.id || ''),
    Group_name: msg.sender_chat?.title || '',
    type,
    file_id,
    caption,
    entities: JSON.stringify(entities),
  }
}];

// Lấy dữ liệu bản dịch từ node Information Extractor
const translations = $('Information Extractor1').item.json.output;

// Lấy thông tin từ sheet (mapping channel theo ngôn ngữ)
const channelId = $('each channel').item.json.Channel;
const language = $('Loop Over Items2').item.json.Language;

const post = $('Limit').all().filter(caption => caption).map(item => item.json.caption).join(', ');

// Lấy file_id ảnh (size lớn nhất) từ message gốc
const photoArr = post?.photo || [];
const bestPhoto = photoArr.length ? photoArr[photoArr.length - 1] : null;
const photoFileId = bestPhoto?.file_id || "";

// Reply id (giữ nguyên logic của bạn)
const replyId = $json['ID_Post'];

// Lấy nội dung tin nhắn theo ngôn ngữ
const messageText = translations[language] || "No translation found";

return {
  chat_id: channelId,
  language,
  text: messageText,

  // Cách 1: gửi ảnh bằng file_id thay vì URL/path
  photo: photoFileId,

  // reply_parameters như cũ
  reply_parameters: replyId ? { message_id: parseInt(replyId, 10) } : null
};

const sourceItems = $("Limit").all();
const sourceRows = sourceItems.map(i => i.json);

const channelItems = $("text matches the channel").all();
const channelData = channelItems[0]?.json || {};

const target_chat_id = String($("Loop Over Items2").first().json.Channel || "").trim();

if (!sourceRows.length || !target_chat_id) return [];

const sharedText = String(channelData.text || "").trim();

const replyMessageId = channelData?.reply_parameters?.message_id || null;
const replyPart = replyMessageId
  ? {
      reply_parameters: {
        message_id: Number(replyMessageId)
      }
    }
  : {};

const groups = {};

for (const r of sourceRows) {
  const key = r.media_group_id
    ? `mg_${r.media_group_id}`
    : `single_${r.message_id}`;

  if (!groups[key]) groups[key] = [];
  groups[key].push(r);
}

const out = [];

for (const [groupKey, arr] of Object.entries(groups)) {
  arr.sort((a, b) => Number(a.message_id || 0) - Number(b.message_id || 0));

  const rowIds = arr
    .map(r => r.id || r.rowId || r._id)
    .filter(Boolean);

  if (arr.length === 1) {
    const r = arr[0];
    const type = String(r.type || "").trim();
    const file_id = r.file_id || null;

    if (type === "photo" && file_id) {
      out.push({
        json: {
          group_key: `${groupKey}_${target_chat_id}`,
          source_group_key: groupKey,
          send_method: "sendPhoto",
          payload: {
            chat_id: target_chat_id,
            photo: file_id,
            ...(sharedText ? { caption: sharedText } : {}),
            ...replyPart
          },
          rows_to_mark: rowIds
        }
      });
      continue;
    }

    if (type === "video" && file_id) {
      out.push({
        json: {
          group_key: `${groupKey}_${target_chat_id}`,
          source_group_key: groupKey,
          send_method: "sendVideo",
          payload: {
            chat_id: target_chat_id,
            video: file_id,
            ...(sharedText ? { caption: sharedText } : {}),
            ...replyPart
          },
          rows_to_mark: rowIds
        }
      });
      continue;
    }

    if (type === "document" && file_id) {
      out.push({
        json: {
          group_key: `${groupKey}_${target_chat_id}`,
          source_group_key: groupKey,
          send_method: "sendDocument",
          payload: {
            chat_id: target_chat_id,
            document: file_id,
            ...(sharedText ? { caption: sharedText } : {}),
            ...replyPart
          },
          rows_to_mark: rowIds
        }
      });
      continue;
    }

    out.push({
      json: {
        group_key: `${groupKey}_${target_chat_id}`,
        source_group_key: groupKey,
        send_method: "sendMessage",
        payload: {
          chat_id: target_chat_id,
          text: sharedText || "Unsupported message type",
          ...replyPart
        },
        rows_to_mark: rowIds
      }
    });

    continue;
  }

  const media = arr
    .filter(r => r.file_id && ["photo", "video"].includes(String(r.type || "").trim()))
    .map((r, idx) => {
      const item = {
        type: String(r.type || "").trim(),
        media: r.file_id
      };

      if (idx === 0 && sharedText) {
        item.caption = sharedText;
      }

      return item;
    });

  if (!media.length) continue;

  out.push({
    json: {
      group_key: `${groupKey}_${target_chat_id}`,
      source_group_key: groupKey,
      media_group_id: arr[0].media_group_id || null,
      send_method: "sendMediaGroup",
      payload: {
        chat_id: target_chat_id,
        media,
        ...replyPart
      },
      rows_to_mark: rowIds
    }
  });
}

return out;

