// Chọn chế độ "Run Once For All Items" trong node Code
return $("Limit").all().map(item => {
  return {
    json: {
      message_id: item.json.message_id
    }
  };
});

// Lấy dữ liệu bản dịch từ node Information Extractor
const translations = $('Information Extractor1').item.json.output;

// Lấy thông tin từ node loop
const loopItem = $('Loop Over Items4').item.json;
const language = loopItem.Language;
const channelId = loopItem.channel_id;

// Lấy nội dung tin nhắn theo ngôn ngữ
const messageText = translations[language] || "No translation found";

return {
  chat_id: channelId,
  language,
  text: messageText,
};

// Chọn chế độ "Run Once For All Items" trong node Code
return $("Limit").all().map(item => {
  return {
    json: {
      message_id: item.json.message_id
    }
  };
});

const input = items[0].json.output;

// Parse languages
const languages = input.language.split(",").map(l => l.trim());

// Regex-safe extract
function extractText(lang) {
  const regex = new RegExp(
    `LANG=${lang}\\|TEXT=([\\s\\S]*?)(?=\\nLANG=|$)`
  );
  const match = input.text.match(regex);
  return match ? match[1] : "";
}

function extractEntities(lang) {
  const regex = new RegExp(
    `LANG=${lang}\\|ENTITIES=(\\[[\\s\\S]*?\\])`
  );
  const match = input.entities.match(regex);
  return match ? JSON.parse(match[1]) : [];
}

// 🔥 IMPORTANT: return EXACTLY 1 ITEM PER LANGUAGE
return languages.map(lang => ({
  json: {
    language: lang,
    text: extractText(lang),      // multiline SAFE
    entities: extractEntities(lang)
  }
}));

// 1. Ngôn ngữ từ Loop (Google Sheet)
const targetLanguage = $json["Ngôn ngữ"];

// 2. Channel ID / username
const channelId = $json.Channel;

// 3. Lấy toàn bộ bản dịch từ Code in JavaScript1
const translations = $("Code in JavaScript5")
  .all()
  .map(item => item.json);

// 4. Match language
const matched = translations.find(
  t => t.language === targetLanguage
);

if (!matched) {
  throw new Error(`❌ Không tìm thấy language: ${targetLanguage}`);
}

// 5. Telegram post gốc
const post = $("Telegram Trigger").first().json.channel_post;

// 6. Lấy ảnh lớn nhất (nếu có)
const photos = post.photo || [];
const bestPhoto = photos.length ? photos[photos.length - 1] : null;
const photoFileId = bestPhoto?.file_id ?? null;

// 7. Build payload cho Telegram
if (photoFileId) {
  return {
    chat_id: channelId,
    method: "sendPhoto",

    photo: photoFileId,
    caption: matched.text,
    caption_entities: matched.entities,

    language: targetLanguage
  };
}

return {
  chat_id: channelId,
  method: "sendMessage",
  text: matched.text,
  entities: matched.entities,
  payload_key: photoFileId ? "caption" : "text",
  photo: photoFileId ,
}

// Chọn chế độ "Run Once For All Items" trong node Code
return $("Limit").all().map(item => {
  return {
    json: {
      message_id: item.json.message_id
    }
  };
});

const itemsIn = $input.all();

if (!itemsIn.length) {
  return [];
}

// Lấy data gốc
const rows = itemsIn.map(item => item.json);

// Sắp xếp để đảm bảo lấy đúng hàng đầu tiên
rows.sort((a, b) => {
  const dateA = new Date(a.created_at || 0).getTime();
  const dateB = new Date(b.created_at || 0).getTime();
  return dateA - dateB;
});

// Lấy hàng đầu tiên
const firstRow = rows[0];

// media_group_id của hàng đầu tiên
const mediaGroupId = firstRow.media_group_id;

// Nếu có media_group_id => lấy toàn bộ hàng cùng group
if (mediaGroupId !== null && mediaGroupId !== undefined && mediaGroupId !== "") {
  const groupedRows = rows.filter(
    row => String(row.media_group_id) === String(mediaGroupId)
  );

  return groupedRows.map(row => ({
    json: row
  }));
}

// Nếu không có media_group_id => chỉ trả về 1 hàng
return [
  {
    json: firstRow
  }
];
